{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1.json",
  "description": "Default-deny MCP policy for @metaharness/example-nasa. Only read-safe NASA API tools are granted. Any operation that mutates state (file writes, shell execution, network beyond api.nasa.gov) requires the --allow-mutations flag and is NOT included here.",
  "mutations_require_flag": "--allow-mutations",
  "defaultDeny": true,
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 12,
  "auditLog": true,
  "audit_log_path": ".harness/audit/nasa-mcp.jsonl",
  "grantedTools": [
    {
      "tool": "WebFetch",
      "description": "Fetch read-only JSON responses from api.nasa.gov endpoints.",
      "allowedHostPatterns": [
        "https://api.nasa.gov/*",
        "https://exoplanetarchive.ipac.caltech.edu/TAP/*"
      ],
      "allowedMethods": ["GET"]
    },
    {
      "tool": "Read",
      "description": "Read local workspace files (agent outputs, cached responses). Scoped to project root.",
      "allowedPathPatterns": ["./**"],
      "deniedPathPatterns": ["./.env", "./.env.*", "**/.git/**"]
    },
    {
      "tool": "Write",
      "description": "Write agent output files to the outputs/ directory only.",
      "allowedPathPatterns": ["./outputs/**"],
      "note": "Write is granted narrowly to outputs/ only. All other write targets are denied. Requires --allow-mutations to expand scope."
    }
  ],
  "deniedTools": [
    {
      "tool": "Bash",
      "reason": "Shell execution is not needed for read-only NASA API queries and is denied unconditionally. Pass --allow-mutations to re-evaluate for specific CI tasks."
    },
    {
      "tool": "WebSearch",
      "reason": "Unscoped web search is not needed; all data comes from api.nasa.gov via WebFetch with allowedHostPatterns."
    }
  ],
  "rateLimits": {
    "note": "NASA DEMO_KEY is capped at 30 requests/hour and 50/day. Set NASA_API_KEY in .env to raise the limit to 1000/hour. The executor agent enforces a minimum 1-second delay between requests."
  }
}
